import type { AnyObject } from "../../_util/type";
import type { ColumnType } from "../types";
import { useTableStore } from "../hooks/use-table";

interface ColGroupProps<TRecord> {
  colWidths: readonly (number | string | undefined)[];
  columns?: readonly ColumnType<TRecord>[];
  columCount?: number;
}
const ColGroup = <TRecord extends AnyObject>({
  colWidths,
  columns,
  columCount,
}: ColGroupProps<TRecord>) => {
  const { tableLayout } = useTableStore((s) => s);

  const cols: React.ReactElement[] = [];
  const len = columCount ?? columns?.length ?? 0;

  // Only insert col with width & additional props
  // Skip if rest col do not have any useful info
  let mustInsert = false;
  for (let i = len - 1; i >= 0; i -= 1) {
    const width = colWidths[i];
    const column = columns?.[i];
    // let additionalProps;
    let minWidth: number | undefined;
    if (column) {
      // additionalProps = column[INTERNAL_COL_DEFINE];

      // fixed will cause layout problems
      if (tableLayout === "auto") {
        minWidth = column.minWidth;
      }
    }

    if (
      width ||
      minWidth ||
      // additionalProps ||
      mustInsert
    ) {
      // const { columnType, ...restAdditionalProps } = additionalProps || {};
      cols.unshift(
        <col
          key={i}
          style={{ width, minWidth }}
          //  {...restAdditionalProps}
        />,
      );
      mustInsert = true;
    }
  }

  return <colgroup>{cols}</colgroup>;
};

export type { ColGroupProps };
export { ColGroup };

"use client";

import type { Column } from "@tanstack/react-table";

import { cn } from "../../../lib/utils";

import type { TableHeadProps } from "./base";
import type { TableLocale } from "../types";
import { TableHead } from "./base";
import { Icon } from "../../../icons";
import { Tooltip } from "../../tooltip";

interface TableHeadAdvancedProps<TData, TValue> extends TableHeadProps {
  column: Column<TData, TValue>;
  locale: TableLocale;
}

export function TableHeadAdvanced<TData, TValue>({
  column,
  children,

  align,
  size,
  className,

  locale,

  onClick: originOnClick,
  ...props
}: TableHeadAdvancedProps<TData, TValue>) {
  if (!column.getCanSort()) {
    return (
      <TableHead size={size} className={cn(className)} {...props}>
        {children}
      </TableHead>
    );
  }
  // const originOnClick = cell.onClick;

  const onClick = (event: React.MouseEvent<HTMLTableHeaderCellElement>) => {
    column.columnDef.meta?.onHeaderCell?.(column.columnDef.meta);
    originOnClick?.(event);
  };

  const nextSortOrder = column.getNextSortingOrder();
  const ariaLabel = column.getIsSorted()
    ? `Sorted ${column.getIsSorted() === "asc" ? "ascending" : "descending"}. Click to ${
        nextSortOrder === "asc"
          ? "sort ascending"
          : nextSortOrder === "desc"
            ? "sort descending"
            : "cancel sort"
      }.`
    : `Not sorted. Click to sort ${nextSortOrder === "asc" ? "ascending" : "descending"}.`;

  return (
    <TableHead
      size={size}
      className={cn("px-1", className)}
      aria-label={ariaLabel}
      onClick={onClick}
      {...props}
      {...column.columnDef.meta?.onHeaderCell?.(column.columnDef.meta)}
    >
      <Tooltip
        title={
          column.getCanSort()
            ? nextSortOrder === "asc"
              ? locale.triggerAsc
              : nextSortOrder === "desc"
                ? locale.triggerDesc
                : locale.cancelSort
            : undefined
        }
        delayDuration={200}
      >
        <div
          className={cn(
            "-my-2 p-2",
            size === "small" && "p-1",
            "flex w-full items-center justify-between",
            "hover:bg-accent hover:text-accent-foreground cursor-pointer rounded-md border-none",
          )}
          onClick={column.getToggleSortingHandler()}
        >
          {align === "center" && <span className="mr-2.5 size-4"></span>}
          <span className="flex-1">{children}</span>
          {column.getCanSort() && column.getIsSorted() === "desc" ? (
            <Icon
              icon="icon-[lucide--arrow-down]"
              className="ml-2.5 size-4"
              aria-hidden="true"
            />
          ) : column.getIsSorted() === "asc" ? (
            <Icon
              icon="icon-[lucide--arrow-up]"
              className="ml-2.5 size-4"
              aria-hidden="true"
            />
          ) : (
            <Icon
              icon="icon-[lucide--chevrons-up-down]"
              className="ml-2.5 size-4"
              aria-hidden="true"
            />
          )}
        </div>
      </Tooltip>
    </TableHead>
  );
}

