type SelectionCheckboxProps = Partial<
  Omit<CheckboxProps, "checked" | "defaultChecked">
>;
type SelectionChangeEvent = Parameters<
  NonNullable<SelectionCheckboxProps["onChange"]>
>[0];
type SelectionMenuItem = {
  key: React.Key;
