  locale: TableLocale;
  getPopupContainer?: GetPopupContainer;
}

export type INTERNAL_SELECTION_ITEM =
  | SelectionItem
  | typeof SELECTION_ALL
  | typeof SELECTION_INVERT
  | typeof SELECTION_NONE;

const flattenData = <RecordType extends AnyObject = AnyObject>(
  childrenColumnName: keyof RecordType,
  data?: RecordType[],
): RecordType[] => {
  let list: RecordType[] = [];
  (data || []).forEach((record) => {
    list.push(record);
    if (record && typeof record === "object" && childrenColumnName in record) {
      list = [
        ...list,
        ...flattenData<RecordType>(
          childrenColumnName,
          record[childrenColumnName],
        ),
      ];
    }
  });
  return list;
};

const useSelection = <RecordType extends AnyObject = AnyObject>(
  config: UseSelectionConfig<RecordType>,
  rowSelection?: TableRowSelection<RecordType>,
): readonly [
  RowSelectionState,
  OnChangeFn<RowSelectionState>,
  TransformColumns<RecordType>,
  Set<Key>,
] => {
  const {
    preserveSelectedRowKeys,
    selectedRowKeys,
    defaultSelectedRowKeys,
    getCheckboxProps,
    onChange: onSelectionChange,
    onSelect,
    onSelectAll,
    onSelectInvert,
    onSelectNone,
    onSelectMultiple,
    columnWidth: selectionColWidth,
    type: selectionType,
    selections,
    fixed,
    renderCell: customizeRenderCell,
    hideSelectAll,
    checkStrictly = true,
  } = rowSelection || {};

  const {
    data,
    pageData,
    getRecordByKey,
    getRowKey,
    expandType,
    childrenColumnName,
    locale: tableLocale,
    getPopupContainer,
  } = config;

  const warning = devUseWarning("Table");

  // ========================= Tanstack Table State =========================
  const [rowSelectionState, setRowSelectionState] =
    useMergedState<RowSelectionState>(
      toRowSelectionState(rowSelection?.defaultSelectedRowKeys),
      {
        value: toRowSelectionState(rowSelection?.selectedRowKeys),
        // onChange: (value) => {
        //   if (!onSelectionChange) return;
        //   onSelectionChange(value);
        // },
      },
    );

  // ========================= MultipleSelect =========================
  const [multipleSelect, updatePrevSelectedIndex] = useMultipleSelect<
    React.Key,
    React.Key
  >((item) => item);

  // ========================= Keys =========================
  const [mergedSelectedKeys, setMergedSelectedKeys] = useMergedState(
    selectedRowKeys || defaultSelectedRowKeys || EMPTY_LIST,
    {
      value: selectedRowKeys,
    },
  );

  // ======================== Caches ========================
  const preserveRecordsRef = React.useRef(new Map<Key, RecordType>());

  const updatePreserveRecordsCache = useCallback(
    (keys: Key[]) => {
      if (preserveSelectedRowKeys) {
        const newCache = new Map<Key, RecordType>();
        // Keep key if mark as preserveSelectedRowKeys
        keys.forEach((key) => {
          let record = getRecordByKey(key);

          if (!record && preserveRecordsRef.current.has(key)) {
            record = preserveRecordsRef.current.get(key)!;
          }

          newCache.set(key, record);
        });
        // Refresh to new cache
        preserveRecordsRef.current = newCache;
      }
    },
    [getRecordByKey, preserveSelectedRowKeys],
  );

  // Update cache with selectedKeys
  React.useEffect(() => {
    updatePreserveRecordsCache(mergedSelectedKeys);
  }, [mergedSelectedKeys]);

  // Get flatten data
  const flattedData = useMemo(
    () => flattenData(childrenColumnName, pageData),
    [childrenColumnName, pageData],
  );

  const { keyEntities } = useMemo(() => {
    if (checkStrictly) {
      return { keyEntities: null };
    }
    let convertData = data;
    if (preserveSelectedRowKeys) {
      // use flattedData keys
      const keysSet = new Set(
        flattedData.map((record, index) => getRowKey(record, index)),
      );
      // remove preserveRecords that duplicate data
      const preserveRecords = [...preserveRecordsRef.current].reduce(
        (total: RecordType[], [key, value]) =>
          keysSet.has(key) ? total : total.concat(value),
        [],
      );
      convertData = [...convertData, ...preserveRecords];
    }
    return convertDataToEntities(convertData as unknown as DataNode[], {
      externalGetKey: getRowKey as any,
      childrenPropName: childrenColumnName,
    });
  }, [
    data,
    getRowKey,
    checkStrictly,
    childrenColumnName,
    preserveSelectedRowKeys,
    flattedData,
  ]);

  // Get all checkbox props
  const checkboxPropsMap = useMemo(() => {
    const map = new Map<
      Key,
      Partial<Omit<CheckboxProps, "checked" | "defaultChecked">>
    >();
    flattedData.forEach((record, index) => {
      const key = getRowKey(record, index);
      const checkboxProps =
        (getCheckboxProps ? getCheckboxProps(record) : null) || {};
      map.set(key, checkboxProps);

      warning(
        !("checked" in checkboxProps || "defaultChecked" in checkboxProps),
        "usage",
        "Do not set `checked` or `defaultChecked` in `getCheckboxProps`. Please use `selectedRowKeys` instead.",
      );
    });
    return map;
  }, [flattedData, getRowKey, getCheckboxProps]);

  const isCheckboxDisabled: GetCheckDisabled<RecordType> = useCallback(
    (r: RecordType) => {
      const rowKey = getRowKey(r, -1);
      let checkboxProps:
        | Partial<Omit<CheckboxProps, "checked" | "defaultChecked">>
        | undefined;
      if (checkboxPropsMap.has(rowKey)) {
        checkboxProps = checkboxPropsMap.get(getRowKey(r, -1));
      } else {
        checkboxProps = getCheckboxProps ? getCheckboxProps(r) : undefined;
      }
      return !!checkboxProps?.disabled;
    },
    [checkboxPropsMap, getRowKey],
  );

  const [derivedSelectedKeys, derivedHalfSelectedKeys] = useMemo(() => {
    if (checkStrictly) {
      return [mergedSelectedKeys, []];
    }
    const { checkedKeys, halfCheckedKeys } = conductCheck(
      mergedSelectedKeys,
      true,
      keyEntities as any,
      isCheckboxDisabled as any,
    );
    return [checkedKeys || [], halfCheckedKeys];
  }, [mergedSelectedKeys, checkStrictly, keyEntities, isCheckboxDisabled]);

  const derivedSelectedKeySet = useMemo<Set<Key>>(() => {
    if (selectionType === "radio") {
      return new Set(derivedSelectedKeys.slice(0, 1));
    }

    return new Set(derivedSelectedKeys);
  }, [derivedSelectedKeys, selectionType]);

  const derivedHalfSelectedKeySet = useMemo<Set<Key>>(
    () =>
      selectionType === "radio" ? new Set() : new Set(derivedHalfSelectedKeys),
    [derivedHalfSelectedKeys, selectionType],
  );

  // Reset if rowSelection reset
  React.useEffect(() => {
    if (!rowSelection) {
      setMergedSelectedKeys(EMPTY_LIST);
    }
  }, [!!rowSelection]);

  const setSelectedKeys = useCallback(
    (keys: Key[], method: RowSelectMethod) => {
      let availableKeys: Key[];
      let records: RecordType[];

      updatePreserveRecordsCache(keys);

      if (preserveSelectedRowKeys) {
        availableKeys = keys;
        records = keys.map((key) => preserveRecordsRef.current.get(key)!);
      } else {
        // Filter key which not exist in the `dataSource`
        availableKeys = [];
        records = [];

        keys.forEach((key) => {
          const record = getRecordByKey(key);
          if (record !== undefined) {
            availableKeys.push(key);
            records.push(record);
          }
        });
      }

      setMergedSelectedKeys(availableKeys);

      onSelectionChange?.(availableKeys, records, { type: method });
    },
    [
      setMergedSelectedKeys,
      getRecordByKey,
      onSelectionChange,
      preserveSelectedRowKeys,
    ],
  );

  // ====================== Selections ======================
  // Trigger single `onSelect` event
  const triggerSingleSelection = useCallback(
    (key: Key, selected: boolean, keys: Key[], event: Event) => {
      if (onSelect) {
        const rows = keys.map((k) => getRecordByKey(k));
        onSelect(getRecordByKey(key), selected, rows, event);
      }

      setSelectedKeys(keys, "single");
    },
    [onSelect, getRecordByKey, setSelectedKeys],
  );

  const mergedSelections = useMemo<SelectionItem[] | null>(() => {
    if (!selections || hideSelectAll) {
      return null;
    }

    const selectionList: INTERNAL_SELECTION_ITEM[] =
      selections === true
        ? [SELECTION_ALL, SELECTION_INVERT, SELECTION_NONE]
        : selections;

    return selectionList
      .map((selection: INTERNAL_SELECTION_ITEM) => {
        if (selection === SELECTION_ALL) {
          return {
            key: "all",
            text: tableLocale.selectionAll,
            onSelect() {
              setSelectedKeys(
                data
                  .map((record, index) => getRowKey(record, index))
                  .filter((key) => {
                    const checkProps = checkboxPropsMap.get(key);
                    return (
                      !checkProps?.disabled || derivedSelectedKeySet.has(key)
                    );
                  }),
                "all",
              );
            },
          };
        }
        if (selection === SELECTION_INVERT) {
          return {
            key: "invert",
            text: tableLocale.selectInvert,
            onSelect() {
              const keySet = new Set(derivedSelectedKeySet);
              pageData.forEach((record, index) => {
                const key = getRowKey(record, index);
                const checkProps = checkboxPropsMap.get(key);

                if (!checkProps?.disabled) {
                  if (keySet.has(key)) {
                    keySet.delete(key);
                  } else {
                    keySet.add(key);
                  }
                }
              });

              const keys = [...keySet];
              if (onSelectInvert) {
                warning.deprecated(false, "onSelectInvert", "onChange");
                onSelectInvert(keys);
              }

              setSelectedKeys(keys, "invert");
            },
          };
        }
        if (selection === SELECTION_NONE) {
          return {
            key: "none",
            text: tableLocale.selectNone,
            onSelect() {
              onSelectNone?.();
              setSelectedKeys(
                [...derivedSelectedKeySet].filter((key) => {
                  const checkProps = checkboxPropsMap.get(key);
                  return checkProps?.disabled;
                }),
                "none",
              );
            },
          };
        }
        return selection;
      })
      .map((selection) => ({
        ...selection,
        onSelect: (...rest) => {
          selection.onSelect?.(...rest);
          updatePrevSelectedIndex(null);
        },
      }));
  }, [
    selections,
    derivedSelectedKeySet,
    pageData,
    getRowKey,
    onSelectInvert,
    setSelectedKeys,
  ]);

  // ======================= Columns ========================
  const transformColumns = useCallback(
    (columns: ColumnsType<RecordType>): ColumnsType<RecordType> => {
      // >>>>>>>>>>> Skip if not exists `rowSelection`
      if (!rowSelection) {
        warning(
          !columns.includes(SELECTION_COLUMN),
          "usage",
          "`rowSelection` is not config but `SELECTION_COLUMN` exists in the `columns`.",
        );

        return columns.filter((col) => col !== SELECTION_COLUMN);
      }

      // >>>>>>>>>>> Support selection
      let cloneColumns = [...columns];
      const keySet = new Set(derivedSelectedKeySet);

      // Record key only need check with enabled
      const recordKeys = flattedData
        .map(getRowKey)
        .filter((key) => !checkboxPropsMap.get(key)!.disabled);
      const checkedCurrentAll = recordKeys.every((key) => keySet.has(key));
      const checkedCurrentSome = recordKeys.some((key) => keySet.has(key));

      const onSelectAllChange = () => {
        const changeKeys: Key[] = [];

        if (checkedCurrentAll) {
          recordKeys.forEach((key) => {
            keySet.delete(key);
            changeKeys.push(key);
          });
        } else {
          recordKeys.forEach((key) => {
            if (!keySet.has(key)) {
              keySet.add(key);
              changeKeys.push(key);
            }
          });
        }

        const keys = [...keySet];

        onSelectAll?.(
          !checkedCurrentAll,
          keys.map((k) => getRecordByKey(k)),
          changeKeys.map((k) => getRecordByKey(k)),
        );

        setSelectedKeys(keys, "all");
        updatePrevSelectedIndex(null);
      };

      // ===================== Render =====================
      // Title Cell
      let title: React.ReactNode;
      let columnTitleCheckbox: React.ReactNode;
      if (selectionType !== "radio") {
        let customizeSelections: React.ReactNode;
        if (mergedSelections) {
          const items = mergedSelections.map((selection, index) => {
            const { key, text, onSelect: onSelectionClick } = selection;

            return {
              key: key ?? index,
              onClick: () => {
                onSelectionClick?.(recordKeys);
              },
              label: text,
            } satisfies SelectionMenuItem;
          });
          customizeSelections = (
            <SelectionActionsDropdown
              getPopupContainer={getPopupContainer}
              items={items}
            />
          );
        }

        const allDisabledData = flattedData
          .map((record, index) => {
            const key = getRowKey(record, index);
            const checkboxProps = checkboxPropsMap.get(key) || {};
            return { checked: keySet.has(key), ...checkboxProps };
          })
          .filter(({ disabled }) => disabled);

        const allDisabled =
          allDisabledData.length > 0 &&
          allDisabledData.length === flattedData.length;

        const allDisabledAndChecked =
          allDisabled && allDisabledData.every(({ checked }) => checked);
        const allDisabledSomeChecked =
          allDisabled && allDisabledData.some(({ checked }) => checked);

        columnTitleCheckbox = (
          <Checkbox
            checked={
              allDisabled
                ? allDisabledAndChecked
                : flattedData.length > 0 && checkedCurrentAll
            }
            indeterminate={
              allDisabled
                ? !allDisabledAndChecked && allDisabledSomeChecked
                : !checkedCurrentAll && checkedCurrentSome
            }
            onChange={onSelectAllChange}
            disabled={flattedData.length === 0 || allDisabled}
            aria-label={customizeSelections ? "Custom selection" : "Select all"}
            skipGroup
          />
        );

        title = !hideSelectAll && (
          <div>
            {columnTitleCheckbox}
            {customizeSelections}
          </div>
        );
      }

      // Body Cell
      let renderCell: (
        _: RecordType,
        record: RecordType,
        index: number,
      ) => { node: React.ReactNode; checked: boolean };
      if (selectionType === "radio") {
        renderCell = (_, record, index) => {
          const key = getRowKey(record, index);
          const checked = keySet.has(key);
          const checkboxProps = checkboxPropsMap.get(key);
          return {
            node: (
              <SelectionRadio
                checked={checked}
                checkboxProps={checkboxProps}
                onChange={(event) => {
                  if (!keySet.has(key)) {
                    triggerSingleSelection(key, true, [key], event.nativeEvent);
                  }
                  checkboxProps?.onChange?.(event);
                }}
              />
            ),
            checked,
          };
        };
      } else {
        renderCell = (_, record, index) => {
          const key = getRowKey(record, index);
          const checked = keySet.has(key);
          const indeterminate = derivedHalfSelectedKeySet.has(key);
          const checkboxProps = checkboxPropsMap.get(key);
          let mergedIndeterminate: boolean;
          if (expandType === "nest") {
            mergedIndeterminate = indeterminate;
            warning(
              typeof checkboxProps?.indeterminate !== "boolean",
              "usage",
              "set `indeterminate` using `rowSelection.getCheckboxProps` is not allowed with tree structured dataSource.",
            );
          } else {
            mergedIndeterminate = checkboxProps?.indeterminate ?? indeterminate;
          }
          // Record checked
          return {
            node: (
              <Checkbox
                // {...checkboxProps}
                indeterminate={mergedIndeterminate}
                checked={checked}
                skipGroup
                onClick={(e) => {
                  e.stopPropagation();
                  checkboxProps?.onClick?.(e);
                }}
                onChange={(event) => {
                  const { nativeEvent } = event;
                  const { shiftKey } = nativeEvent;
                  const currentSelectedIndex = recordKeys.indexOf(key);
                  const isMultiple = derivedSelectedKeys.some((item) =>
                    recordKeys.includes(item),
                  );

                  if (shiftKey && checkStrictly && isMultiple) {
                    const changedKeys = multipleSelect(
                      currentSelectedIndex,
                      recordKeys,
                      keySet,
                    );
                    const keys = [...keySet];

                    onSelectMultiple?.(
                      !checked,
                      keys.map((recordKey) => getRecordByKey(recordKey)),
                      changedKeys.map((recordKey) => getRecordByKey(recordKey)),
                    );

                    setSelectedKeys(keys, "multiple");
                  } else {
                    // Single record selected
                    const originCheckedKeys = derivedSelectedKeys;
                    if (checkStrictly) {
                      const checkedKeys = checked
                        ? arrDel(originCheckedKeys, key)
                        : arrAdd(originCheckedKeys, key);
                      triggerSingleSelection(
                        key,
                        !checked,
                        checkedKeys,
                        nativeEvent,
                      );
                    } else {
                      // Always fill first
                      const result = conductCheck(
                        [...originCheckedKeys, key],
                        true,
                        keyEntities as any,
                        isCheckboxDisabled as any,
                      );
                      const { checkedKeys, halfCheckedKeys } = result;
                      let nextCheckedKeys = checkedKeys;

                      // If remove, we do it again to correction
                      if (checked) {
                        const tempKeySet = new Set(checkedKeys);
                        tempKeySet.delete(key);
                        nextCheckedKeys = conductCheck(
                          [...tempKeySet],
                          { checked: false, halfCheckedKeys },
                          keyEntities as any,
                          isCheckboxDisabled as any,
                        ).checkedKeys;
                      }

                      triggerSingleSelection(
                        key,
                        !checked,
                        nextCheckedKeys,
                        nativeEvent,
                      );
                    }
                  }

                  if (checked) {
                    updatePrevSelectedIndex(null);
                  } else {
                    updatePrevSelectedIndex(currentSelectedIndex);
                  }
                  checkboxProps?.onChange?.(event);
                }}
              />
            ),
            checked,
          };
        };
      }

      const renderSelectionCell = (
        _: any,
        record: RecordType,
        index: number,
      ) => {
        const { node, checked } = renderCell(_, record, index);

        if (customizeRenderCell) {
          return customizeRenderCell(checked, record, index, node);
        }

        return node;
      };

      // Insert selection column if not exist
      if (!cloneColumns.includes(SELECTION_COLUMN)) {
        // Always after expand icon
        if (
          cloneColumns.findIndex(
            (col: any) =>
              col[INTERNAL_COL_DEFINE]?.columnType === "EXPAND_COLUMN",
          ) === 0
        ) {
          const [expandColumn, ...restColumns] = cloneColumns;
          cloneColumns = [expandColumn!, SELECTION_COLUMN, ...restColumns];
        } else {
          // Normal insert at first column
          cloneColumns = [SELECTION_COLUMN, ...cloneColumns];
        }
      }

      // Deduplicate selection column
      const selectionColumnIndex = cloneColumns.indexOf(SELECTION_COLUMN);

      warning(
        cloneColumns.filter((col) => col === SELECTION_COLUMN).length <= 1,
        "usage",
        "Multiple `SELECTION_COLUMN` exist in `columns`.",
      );

      cloneColumns = cloneColumns.filter(
        (column, index) =>
          column !== SELECTION_COLUMN || index === selectionColumnIndex,
      );

      // Fixed column logic
      const prevCol: ColumnType<RecordType> & Record<string, any> =
        cloneColumns[selectionColumnIndex - 1]!;
      const nextCol: ColumnType<RecordType> & Record<string, any> =
        cloneColumns[selectionColumnIndex + 1]!;

      let mergedFixed: FixedType | undefined = fixed;

      if (mergedFixed === undefined) {
        if (nextCol?.fixed !== undefined) {
          mergedFixed = nextCol.fixed;
        } else if (prevCol?.fixed !== undefined) {
          mergedFixed = prevCol.fixed;
        }
      }

      if (
        mergedFixed &&
        prevCol &&
        prevCol[INTERNAL_COL_DEFINE]?.columnType === "EXPAND_COLUMN" &&
        prevCol.fixed === undefined
      ) {
        prevCol.fixed = mergedFixed;
      }

      // const columnCls = classNames(`${prefixCls}-selection-col`, {
      //   [`${prefixCls}-selection-col-with-dropdown`]:
      //     selections && selectionType === "checkbox",
      // });

      const renderColumnTitle = () => {
        if (!rowSelection?.columnTitle) {
          return title;
        }
        if (typeof rowSelection.columnTitle === "function") {
          return rowSelection.columnTitle(columnTitleCheckbox);
        }
        return rowSelection.columnTitle;
      };

      // Replace with real selection column
      const selectionColumn: ColumnsType<RecordType>[0] & {
        RC_TABLE_INTERNAL_COL_DEFINE: Record<string, any>;
      } = {
        fixed: mergedFixed,
        width: selectionColWidth,
        // className: `${prefixCls}-selection-column`,
        title: renderColumnTitle(),
        render: renderSelectionCell,
        onCell: rowSelection.onCell,
        align: rowSelection.align,
        [INTERNAL_COL_DEFINE]: { className: "" },
      };

      return cloneColumns.map((col) =>
        col === SELECTION_COLUMN ? selectionColumn : col,
      );
    },
    [
      getRowKey,
      flattedData,
      rowSelection,
      derivedSelectedKeys,
      derivedSelectedKeySet,
      derivedHalfSelectedKeySet,
      selectionColWidth,
      mergedSelections,
      expandType,
      checkboxPropsMap,
      onSelectMultiple,
      triggerSingleSelection,
      isCheckboxDisabled,
    ],
  );

  return [
    rowSelectionState,
    setRowSelectionState,
    transformColumns,
    derivedSelectedKeySet,
  ] as const;
};

export default useSelection;

/* eslint-disable @typescript-eslint/no-non-null-assertion */
/* eslint-disable unicorn/prefer-ternary */

/* eslint-disable unicorn/no-array-callback-reference */
/* eslint-disable react-hooks/exhaustive-deps */
/* eslint-disable unicorn/explicit-length-check */

import type { OnChangeFn, SortingState } from "@tanstack/react-table";
import React from "react";
import KeyCode from "@rc-component/util/lib/KeyCode";

import type { AnyObject } from "../../_util/type";
import type { TooltipProps } from "../../tooltip";
import type {
  ColumnGroupType,
  ColumnsType,
  ColumnTitleProps,
  ColumnType,
  Key,
  SorterResult,
  SorterTooltipProps,
  SortOrder,
  TableLocale,
  TransformColumns,
} from "../types";
import { Icon } from "../../../icons";
import { cn } from "../../../lib/utils";
import { Tooltip } from "../../tooltip";
import {
  getColumnKey,
  getColumnPos,
  renderColumnTitle,
  safeColumnTitle,
} from "../util";

const ASCEND = "ascend";
const DESCEND = "descend";

const getMultiplePriority = <RecordType extends AnyObject = AnyObject>(
  column: ColumnType<RecordType>,
): number | false => {
  if (
    typeof column.sorter === "object" &&
    typeof column.sorter.multiple === "number"
  ) {
    return column.sorter.multiple;
  }
  return false;
};

const nextSortDirection = (
  sortDirections: SortOrder[],
  current: SortOrder | null,
) => {
  if (!current) {
    return sortDirections[0]!;
  }
  return sortDirections[sortDirections.indexOf(current) + 1]!;
};

export interface SortState<RecordType = AnyObject> {
  column: ColumnType<RecordType>;
  key: Key;
  sortOrder: SortOrder | null;
  multiplePriority: number | false;
}

const collectSortStates = <RecordType extends AnyObject = AnyObject>(
  columns: ColumnsType<RecordType>,
  init: boolean,
  pos?: string,
): SortState<RecordType>[] => {
  let sortStates: SortState<RecordType>[] = [];

  const pushState = (
    column: ColumnsType<RecordType>[number],
    columnPos: string,
  ) => {
    sortStates.push({
      column: column as ColumnType<RecordType>,
      key: getColumnKey<RecordType>(
        column as ColumnType<RecordType>,
        columnPos,
      ),
      multiplePriority: getMultiplePriority<RecordType>(
        column as ColumnType<RecordType>,
      ),
      sortOrder: (column as ColumnType<RecordType>).sortOrder!,
    });
  };

  for (const [index, column] of (columns || []).entries()) {
    const columnPos = getColumnPos(index, pos);
    if ((column as ColumnGroupType<RecordType>).children) {
      if ("sortOrder" in column) {
        // Controlled
        pushState(column, columnPos);
      }
      sortStates = [
        ...sortStates,
        ...collectSortStates<RecordType>(
          (column as ColumnGroupType<RecordType>).children,
          init,
          columnPos,
        ),
      ];
    } else if (column.sorter) {
      if ("sortOrder" in column) {
        // Controlled
        pushState(column, columnPos);
      } else if (init && column.defaultSortOrder) {
        // Default sorter
        sortStates.push({
          column,
          key: getColumnKey(column, columnPos),
          multiplePriority: getMultiplePriority<RecordType>(column),
          sortOrder: column.defaultSortOrder,
        });
      }
    }
  }

  return sortStates;
};

const injectSorter = <RecordType extends AnyObject = AnyObject>(
  columns: ColumnsType<RecordType>,
  sorterStates: SortState<RecordType>[],
  triggerSorter: (sorterSates: SortState<RecordType>) => void,
  defaultSortDirections: SortOrder[],
  tableLocale?: TableLocale,
  tableShowSorterTooltip?: boolean | SorterTooltipProps,
  pos?: string,
): ColumnsType<RecordType> => {
  return (columns || []).map((column, index) => {
    const columnPos = getColumnPos(index, pos);
    let newColumn: ColumnsType<RecordType>[number] = column;
    if (newColumn.sorter) {
      const sortDirections: SortOrder[] =
        newColumn.sortDirections || defaultSortDirections;
      const showSorterTooltip =
        newColumn.showSorterTooltip === undefined
          ? tableShowSorterTooltip
          : newColumn.showSorterTooltip;

      const columnKey = getColumnKey(newColumn, columnPos);
      const sorterState = sorterStates.find(({ key }) => key === columnKey);
      const sortOrder = sorterState ? sorterState.sortOrder : null;
      const nextSortOrder = nextSortDirection(sortDirections, sortOrder);

      let sorter: React.ReactNode;
      if (column.sortIcon) {
        sorter = column.sortIcon({ sortOrder });
      } else {
        const upNode: React.ReactNode = sortDirections.includes(ASCEND) && (
          <Icon
            icon="icon-[ant-design--caret-down-outlined]"
            className={cn(`column-sorter-up`, {
              active: sortOrder === ASCEND,
            })}
          />
        );
        const downNode: React.ReactNode = sortDirections.includes(DESCEND) && (
          <Icon
            icon="icon-[ant-design--caret-down-outlined]"
            className={cn(`column-sorter-down`, {
              active: sortOrder === DESCEND,
            })}
          />
        );
        sorter = (
          <span
            className={cn(`column-sorter`, {
              "column-sorter-full": !!(upNode && downNode),
            })}
          >
            <span className="column-sorter-inner" aria-hidden="true">
              {upNode}
              {downNode}
            </span>
          </span>
        );
      }

      const { cancelSort, triggerAsc, triggerDesc } = tableLocale || {};
      let sortTip: string | undefined = cancelSort;
      if (nextSortOrder === DESCEND) {
        sortTip = triggerDesc;
      } else if (nextSortOrder === ASCEND) {
        sortTip = triggerAsc;
      }
      const tooltipProps: TooltipProps =
        typeof showSorterTooltip === "object"
          ? {
              title: sortTip,
              ...showSorterTooltip,
            }
          : { title: sortTip };
      newColumn = {
        ...newColumn,
        className: cn(newColumn.className, { "column-sort": sortOrder }),
        title: (renderProps: ColumnTitleProps<RecordType>) => {
          const columnSortersClass = "column-sorters";
          const renderColumnTitleWrapper = (
            <span className="column-title">
              {renderColumnTitle(column.title, renderProps)}
            </span>
          );
          const renderSortTitle = (
            <div className={columnSortersClass}>
              {renderColumnTitleWrapper}
              {sorter}
            </div>
          );
          if (showSorterTooltip) {
            if (
              typeof showSorterTooltip !== "boolean" &&
              showSorterTooltip?.target === "sorter-icon"
            ) {
              return (
                <div
                  className={cn(
                    `${columnSortersClass} column-sorters-tooltip-target-sorter`,
                  )}
                >
                  {renderColumnTitleWrapper}
                  <Tooltip {...tooltipProps}>{sorter}</Tooltip>
                </div>
              );
            }
            return <Tooltip {...tooltipProps}>{renderSortTitle}</Tooltip>;
          }
          return renderSortTitle;
        },
        onHeaderCell: (col) => {
          const cell: React.HTMLAttributes<HTMLElement> =
            column.onHeaderCell?.(col) || {};
          const originOnClick = cell.onClick;
          const originOKeyDown = cell.onKeyDown;
          cell.onClick = (event: React.MouseEvent<HTMLElement>) => {
            triggerSorter({
              column,
              key: columnKey,
              sortOrder: nextSortOrder,
              multiplePriority: getMultiplePriority<RecordType>(column),
            });
            originOnClick?.(event);
          };
          cell.onKeyDown = (event: React.KeyboardEvent<HTMLElement>) => {
            if (event.keyCode === KeyCode.ENTER) {
              triggerSorter({
                column,
                key: columnKey,
                sortOrder: nextSortOrder,
                multiplePriority: getMultiplePriority<RecordType>(column),
              });
              originOKeyDown?.(event);
            }
          };

          const renderTitle = safeColumnTitle(column.title, {});
          const displayTitle = renderTitle?.toString();

          // Inform the screen-reader so it can tell the visually impaired user which column is sorted
          if (sortOrder) {
            cell["aria-sort"] =
              sortOrder === "ascend" ? "ascending" : "descending";
          }
          cell["aria-label"] = displayTitle || "";
          cell.className = cn(cell.className, "column-has-sorters");
          cell.tabIndex = 0;
          if (column.ellipsis) {
            cell.title = (renderTitle ?? "").toString();
          }
          return cell;
        },
      };
    }

    if ("children" in newColumn) {
      newColumn = {
        ...newColumn,
        children: injectSorter(
          newColumn.children,
          sorterStates,
          triggerSorter,
          defaultSortDirections,
          tableLocale,
          tableShowSorterTooltip,
          columnPos,
        ),
      };
    }

    return newColumn;
  });
};

const stateToInfo = <RecordType extends AnyObject = AnyObject>(
  sorterState: SortState<RecordType>,
): SorterResult<RecordType> => {
  const { column, sortOrder } = sorterState;
  return {
    column,
    order: sortOrder,
    field: column.dataIndex as SorterResult<RecordType>["field"],
    columnKey: column.key,
  };
};
const generateSorterInfo = <RecordType extends AnyObject = AnyObject>(
  sorterStates: SortState<RecordType>[],
): SorterResult<RecordType> | SorterResult<RecordType>[] => {
  const activeSorters = sorterStates
    .filter(({ sortOrder }) => sortOrder)
    .map<SorterResult<RecordType>>(stateToInfo);

  // =========== Legacy compatible support ===========
  // https://github.com/ant-design/ant-design/pull/19226
  if (activeSorters.length === 0 && sorterStates.length > 0) {
    const lastIndex = sorterStates.length - 1;
    return {
      ...stateToInfo(sorterStates[lastIndex]!),
      column: undefined,
      order: undefined,
      field: undefined,
      columnKey: undefined,
    };
  }

  if (activeSorters.length <= 1) {
    return activeSorters[0] || {};
  }

  return activeSorters;
};

interface SorterConfig<RecordType = AnyObject> {
  mergedColumns: ColumnsType<RecordType>;
  onSorterChange: (
    sorterResult: SorterResult<RecordType> | SorterResult<RecordType>[],
    sortStates: SortState<RecordType>[],
  ) => void;
  sortDirections: SortOrder[];
  tableLocale?: TableLocale;
  showSorterTooltip?: boolean | SorterTooltipProps;
}

export const useFilterSorter = <RecordType extends AnyObject = AnyObject>(
  props: SorterConfig<RecordType>,
): [
  SortingState,
  OnChangeFn<SortingState>,
  TransformColumns<RecordType>,
  SortState<RecordType>[],
  ColumnTitleProps<RecordType>,
  () => SorterResult<RecordType> | SorterResult<RecordType>[],
] => {
  const {
    mergedColumns,
    sortDirections,
    tableLocale,
    showSorterTooltip,
    onSorterChange,
  } = props;

  const [sortStates, setSortStates] = React.useState<SortState<RecordType>[]>(
    () => collectSortStates<RecordType>(mergedColumns, true),
  );

  // Calculate initial sorting state from columns with defaultSortOrder
  const initialSortingState: SortingState = React.useMemo(() => {
    const sortingColumns: SortingState = [];

    // Use collectSortStates to properly extract columns with defaultSortOrder
    const sortStates = collectSortStates<RecordType>(mergedColumns, true);

    for (const sortState of sortStates) {
      if (sortState.sortOrder) {
        sortingColumns.push({
          id: sortState.key as string,
          desc: sortState.sortOrder === "descend",
        });
      }
    }

    return sortingColumns;
  }, [mergedColumns]);

  const [sortingState, setSortingState] =
    React.useState<SortingState>(initialSortingState);

  // Update sortingState when columns change with defaultSortOrder
  React.useEffect(() => {
    const sortingColumns: SortingState = [];

    // Use collectSortStates to properly extract columns with defaultSortOrder
    const sortStates = collectSortStates<RecordType>(mergedColumns, true);

    for (const sortState of sortStates) {
      if (sortState.sortOrder) {
        sortingColumns.push({
          id: sortState.key as string,
          desc: sortState.sortOrder === "descend",
        });
      }
    }

    setSortingState(sortingColumns);
  }, [mergedColumns]);

  const handleSortingChange: OnChangeFn<SortingState> = React.useCallback(
    (updaterOrValue) => {
      const newSorting =
        typeof updaterOrValue === "function"
          ? updaterOrValue(sortingState)
          : updaterOrValue;

      setSortingState(newSorting);

      const updatedSortStates: SortState<RecordType>[] = [];
      const sorterResults: SorterResult<RecordType>[] = [];

      for (const [_index, sort] of newSorting.entries()) {
        const column = mergedColumns.find((col) => col.key === sort.id);
        if (!column) continue;
        const order = sort.desc ? "descend" : "ascend";
        const sorterResult: SorterResult<RecordType> = {
          column,
          columnKey: column.key as Key,
          field: (column as ColumnType<RecordType>).dataIndex as Key,
          order,
        };

        updatedSortStates.push({
          column,
          key: sort.id,
          sortOrder: order,
          multiplePriority:
            typeof column.sorter === "object"
              ? (column.sorter.multiple ?? false)
              : false,
        });
        sorterResults.push(sorterResult);
      }

      setSortStates(updatedSortStates);

      if (sorterResults.length <= 1) {
        onSorterChange(sorterResults[0]!, updatedSortStates);
      } else {
        onSorterChange(sorterResults, updatedSortStates);
      }
    },
    [mergedColumns, sortingState, onSorterChange],
  );

  const triggerSorter = React.useCallback(
    (sortState: SortState<RecordType>) => {
      let newSorterStates: SortState<RecordType>[];
      if (
        sortState.multiplePriority === false ||
        !sortStates.length ||
        sortStates[0]?.multiplePriority === false
      ) {
        newSorterStates = [sortState];
      } else {
        newSorterStates = [
          ...sortStates.filter(({ key }) => key !== sortState.key),
          sortState,
        ];
      }
      setSortStates(newSorterStates);
      onSorterChange(generateSorterInfo(newSorterStates), newSorterStates);
    },
    [sortStates, onSorterChange],
  );

  const columnTitleSorterProps = React.useMemo<
    ColumnTitleProps<RecordType>
  >(() => {
    const sortColumns = sortStates.map(({ column, sortOrder }) => ({
      column,
      order: sortOrder,
    }));

    return {
      sortColumns,
      // Legacy
      sortColumn: sortColumns[0]?.column,
      sortOrder: sortColumns[0]?.order,
    };
  }, [sortStates]);

  const transformColumns = React.useCallback(
    (innerColumns: ColumnsType<RecordType>) =>
      injectSorter<RecordType>(
        innerColumns,
        sortStates,
        triggerSorter,
        sortDirections,
        tableLocale,
        showSorterTooltip,
      ),
    [sortStates, sortDirections, tableLocale, showSorterTooltip],
  );

  const getSorters = React.useCallback(
    () => generateSorterInfo<RecordType>(sortStates),
    [sortStates],
  );

  return [
    sortingState,
    handleSortingChange,
    transformColumns,
    sortStates,
    columnTitleSorterProps,
    getSorters,
  ];
};

export default useFilterSorter;

